package handlers

import (
	"context"
	"database/sql"
	"encoding/json"
	"log"
	"net/http"

	"github.com/go-chi/chi/v5"
	"github.com/go-chi/chi/v5/middleware"
)

type Order struct {
	ID       string `json:"id"`
	Customer string `json:"customer"`
	Status   string `json:"status"`
}

func (h *Handler) getOrderDetails(w http.ResponseWriter, r *http.Request) {
	ctx := r.Context()
	userID := ctx.Value("user").(string)
	orderID := chi.URLParam(r, "order_id")

	db := h.DB
	query := `
		SELECT 
			o.id,
			c.name AS customer,
			o.status
		FROM 
			orders o
		JOIN 
			customers c ON o.customer_id = c.id
		WHERE 
			o.id = $1 AND c.user_id = $2;
	`

	var order Order
	err := db.QueryRow(ctx, query, orderID, userID).Scan(&order.ID, &order.Customer, &order.Status)
	if err != nil {
		if err == sql.ErrNoRows {
			http.Error(w, "Order not found", http.StatusNotFound)
			return
		}
		log.Printf("Error fetching order details: %v", err)
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
		return
	}

	json.NewEncoder(w).Encode(order)
}